defmodule DevOpsAutomation.CommandService do
  @moduledoc """
  Service for executing shell commands safely with command injection prevention.
  """

  # Allowlist of permitted commands
  @allowed_commands ~w(ls cat echo grep find df du free uptime whoami date hostname uname ps top head tail wc sort uniq pwd env printenv docker kubectl helm terraform ansible)

  # Dangerous characters/patterns that indicate injection attempts
  @dangerous_patterns [
    ~r/[;|&`$]/,
    ~r/\$\(/,
    ~r/\)\s*\{/,
    ~r/>\s*/,
    ~r/<\s*/,
    ~r/\.\./,
    ~r/\/etc\/shadow/,
    ~r/\/etc\/passwd/,
    ~r/rm\s+-rf/,
    ~r/mkfs/,
    ~r/dd\s+if=/,
    ~r/\beval\b/,
    ~r/\bexec\b/,
    ~r/\bsource\b/,
    ~r/\bsudo\b/,
    ~r/\bsu\b/,
    ~r/\n/,
    ~r/\r/,
    ~r/\x00/
  ]

  @type result :: {:ok, %{output: String.t(), exit_code: non_neg_integer()}} | {:error, String.t()}

  @doc """
  Executes a command safely by validating against an allowlist and checking for injection patterns.

  ## Parameters
    - command: The base command to execute (must be in the allowlist)
    - args: A list of string arguments to pass to the command

  ## Examples
      iex> DevOpsAutomation.CommandService.execute("ls", ["-la", "/tmp"])
      {:ok, %{output: "...", exit_code: 0}}

      iex> DevOpsAutomation.CommandService.execute("rm", ["-rf", "/"])
      {:error, "Command 'rm' is not in the allowed commands list"}
  """
  @spec execute(String.t(), list(String.t())) :: result()
  def execute(command, args \\ []) when is_binary(command) and is_list(args) do
    with :ok <- validate_command(command),
         :ok <- validate_args(args),
         sanitized_args <- sanitize_args(args) do
      run_command(command, sanitized_args)
    end
  end

  @doc """
  Returns the list of allowed commands.
  """
  @spec allowed_commands() :: list(String.t())
  def allowed_commands, do: @allowed_commands

  # Private functions

  defp validate_command(command) do
    # Strip any path components - only allow bare command names
    base_command = command |> String.trim() |> Path.basename()

    cond do
      base_command != command |> String.trim() ->
        {:error, "Command must not contain path separators. Use bare command names only."}

      base_command not in @allowed_commands ->
        {:error,
         "Command '#{base_command}' is not in the allowed commands list. Allowed: #{Enum.join(@allowed_commands, ", ")}"}

      true ->
        :ok
    end
  end

  defp validate_args(args) do
    args
    |> Enum.with_index()
    |> Enum.reduce_while(:ok, fn {arg, index}, :ok ->
      if contains_dangerous_pattern?(arg) do
        {:halt, {:error, "Argument at position #{index} contains potentially dangerous characters: '#{sanitize_for_display(arg)}'"}}
      else
        {:cont, :ok}
      end
    end)
  end

  defp contains_dangerous_pattern?(arg) when is_binary(arg) do
    Enum.any?(@dangerous_patterns, fn pattern ->
      Regex.match?(pattern, arg)
    end)
  end

  defp contains_dangerous_pattern?(_), do: true

  defp sanitize_args(args) do
    Enum.map(args, fn arg ->
      arg
      |> String.trim()
      |> String.replace(~r/[^\w\s\-\.\/\*\?\[\]:@=,+]/, "")
    end)
  end

  defp sanitize_for_display(arg) do
    arg
    |> String.slice(0, 50)
    |> String.replace(~r/[^\w\s\-\.]/, "*")
  end

  defp run_command(command, args) do
    # Use System.cmd with the command and args directly - NOT through sh -c
    # This avoids shell interpretation entirely
    command_path = find_command_path(command)

    case command_path do
      nil ->
        {:error, "Command '#{command}' not found in system PATH"}

      path ->
        try do
          {output, exit_code} =
            System.cmd(path, args,
              stderr_to_stdout: true,
              env: sanitized_env(),
              # Limit output to prevent memory exhaustion
              max_output: 1_048_576
            )

          {:ok, %{output: output, exit_code: exit_code}}
        rescue
          e in ErlangError ->
            {:error, "Command execution failed: #{inspect(e)}"}
        end
    end
  end

  defp find_command_path(command) do
    # Use System.find_executable to locate the command safely
    System.find_executable(command)
  end

  defp sanitized_env do
    # Provide a minimal, safe environment
    [
      {"PATH", "/usr/local/bin:/usr/bin:/bin"},
      {"HOME", "/tmp"},
      {"LANG", "en_US.UTF-8"},
      {"LC_ALL", "en_US.UTF-8"}
    ]
  end
end

defmodule DevOpsAutomation.CommandController do
  use Phoenix.Controller, namespace: DevOpsAutomation

  import Plug.Conn

  alias DevOpsAutomation.CommandService

  @max_args 20
  @max_arg_length 256

  def execute(conn, params) do
    with {:ok, command} <- extract_command(params),
         {:ok, args} <- extract_args(params),
         {:ok, result} <- CommandService.execute(command, args) do
      conn
      |> put_status(:ok)
      |> json(%{
        status: "success",
        command: command,
        output: result.output,
        exit_code: result.exit_code
      })
    else
      {:error, reason} ->
        conn
        |> put_status(:bad_request)
        |> json(%{
          status: "error",
          message: reason
        })
    end
  end

  def list_commands(conn, _params) do
    conn
    |> put_status(:ok)
    |> json(%{
      status: "success",
      allowed_commands: CommandService.allowed_commands()
    })
  end

  # Private functions

  defp extract_command(%{"command" => command}) when is_binary(command) do
    trimmed = String.trim(command)

    cond do
      String.length(trimmed) == 0 ->
        {:error, "Command cannot be empty"}

      String.length(trimmed) > 64 ->
        {:error, "Command name too long (max 64 characters)"}

      true ->
        {:ok, trimmed}
    end
  end

  defp extract_command(_), do: {:error, "Missing or invalid 'command' parameter"}

  defp extract_args(%{"args" => args}) when is_list(args) do
    cond do
      length(args) > @max_args ->
        {:error, "Too many arguments (max #{@max_args})"}

      not Enum.all?(args, &is_binary/1) ->
        {:error, "All arguments must be strings"}

      Enum.any?(args, fn arg -> String.length(arg) > @max_arg_length end) ->
        {:error, "Argument too long (max #{@max_arg_length} characters per argument)"}

      true ->
        {:ok, args}
    end
  end

  defp extract_args(%{"args" => args}) when is_binary(args) do
    # If a single string is passed, split it safely
    split_args = String.split(args, ~r/\s+/, trim: true)
    extract_args(%{"args" => split_args})
  end

  defp extract_args(%{"args" => _}), do: {:error, "Arguments must be a list of strings"}
  defp extract_args(_), do: {:ok, []}
end

defmodule DevOpsAutomation.Router do
  use Phoenix.Router

  import Plug.Conn
  import Phoenix.Controller

  pipeline :api do
    plug :accepts, ["json"]
  end

  scope "/api/v1", DevOpsAutomation do
    pipe_through :api

    post "/execute", CommandController, :execute
    get "/commands", CommandController, :list_commands
  end
end